import { ContextBuilder } from '../context-builder';
import { Optional } from '../context';
import { ChainCondition, CustomCondition } from '../context-items';
import { CustomValidator } from '../base';
import { Bail } from '../context-items/bail';
import { BailOptions, ContextHandler, OptionalOptions } from './context-handler';
import { ContextRunner } from './context-runner';

export class ContextHandlerImpl<Chain> implements ContextHandler<Chain> {
  constructor(private readonly builder: ContextBuilder, private readonly chain: Chain) {}

  bail(opts?: BailOptions) {
    if (opts?.level === 'request') {
      this.builder.setRequestBail();
    }
    this.builder.addItem(new Bail());
    return this.chain;
  }

  if(condition: CustomValidator | ContextRunner) {
    if ('run' in condition) {
      this.builder.addItem(new ChainCondition(condition));
    } else if (typeof condition === 'function') {
      this.builder.addItem(new CustomCondition(condition));
    } else {
      throw new Error('express-validator: condition is not a validation chain nor a function');
    }
    return this.chain;
  }

  optional(options: OptionalOptions | boolean = true) {
    let value: Optional;
    if (typeof options === 'boolean') {
      value = options ? 'undefined' : false;
    } else {
      value = options.values
        ? options.values
        : options.checkFalsy
        ? 'falsy'
        : options.nullable
        ? 'null'
        : 'undefined';
    }

    this.builder.setOptional(value);
    return this.chain;
  }

  hide(hiddenValue?: string) {
    this.builder.setHidden(true, hiddenValue);
    return this.chain;
  }
}

import { ContextItem } from './context-items';
import { Context, Optional, ValueVisibility } from './context';
import { Location } from './base';

export class ContextBuilder {
  private readonly stack: ContextItem[] = [];
  private fields: string[] = [];
  private locations: Location[] = [];
  private message: any;
  private optional: Optional = false;
  private requestBail = false;
  private visibility: ValueVisibility = { type: 'visible' };

  setFields(fields: string[]) {
    this.fields = fields;
    return this;
  }

  setLocations(locations: Location[]) {
    this.locations = locations;
    return this;
  }

  setMessage(message: any) {
    this.message = message;
    return this;
  }

  addItem(...items: ContextItem[]) {
    this.stack.push(...items);
    return this;
  }

  setOptional(options: Optional) {
    this.optional = options;
    return this;
  }

  setRequestBail() {
    this.requestBail = true;
    return this;
  }

  setHidden(hidden: boolean, hiddenValue?: string) {
    if (hidden) {
      this.visibility =
        hiddenValue !== undefined ? { type: 'redacted', value: hiddenValue } : { type: 'hidden' };
    } else {
      this.visibility = { type: 'visible' };
    }
    return this;
  }

  build() {
    return new Context(
      this.fields,
      this.locations,
      this.stack,
      this.optional,
      this.requestBail,
      this.visibility,
      this.message,
    );
  }
}
